import struct
import zlib


_LENGTH = struct.Struct(">I")
_CHECKSUM = struct.Struct(">I")


class IncompleteFrame(Exception):
    pass


class CorruptFrame(Exception):
    pass


def frame_text(text):
    payload = text.encode("utf-8")
    declared_length = len(text)
    checksum = zlib.crc32(payload) & 0xFFFFFFFF
    return _LENGTH.pack(declared_length) + payload + _CHECKSUM.pack(checksum)


def extract_frame(buffer):
    if len(buffer) < _LENGTH.size:
        raise IncompleteFrame()
    payload_size = _LENGTH.unpack(buffer[: _LENGTH.size])[0]
    frame_size = _LENGTH.size + payload_size + _CHECKSUM.size
    if len(buffer) < frame_size:
        raise IncompleteFrame()
    payload_start = _LENGTH.size
    payload_end = payload_start + payload_size
    payload = buffer[payload_start:payload_end]
    expected = _CHECKSUM.unpack(buffer[payload_end:frame_size])[0]
    actual = zlib.crc32(payload) & 0xFFFFFFFF
    if actual != expected:
        raise CorruptFrame("checksum mismatch")
    try:
        text = payload.decode("utf-8")
    except UnicodeDecodeError as error:
        raise CorruptFrame("invalid UTF-8") from error
    return text, frame_size

