from relay_protocol.codec import EventCodec
from relay_protocol.framing import IncompleteFrame, extract_frame, frame_text


class EventGateway:
    def __init__(self, codec=None):
        self._codec = codec or EventCodec()
        self._buffer = bytearray()

    def outbound(self, event):
        return frame_text(self._codec.encode(event))

    def feed(self, chunk):
        self._buffer = bytearray(chunk)
        events = []
        while self._buffer:
            try:
                text, consumed = extract_frame(bytes(self._buffer))
            except IncompleteFrame:
                break
            events.append(self._codec.decode(text))
            del self._buffer[:consumed]
        return events

