from relay_protocol.gateway import EventGateway


def test_complete_ascii_event_round_trips_with_truthy_metadata():
    gateway = EventGateway()
    event = {
        "type": "delivery",
        "body": {"label": "west", "count": 4},
        "attempt": 2,
        "durable": True,
        "trace": "trace-11",
    }
    assert gateway.feed(gateway.outbound(event)) == [event]


def test_multiple_complete_ascii_frames_can_share_one_chunk():
    sender = EventGateway()
    receiver = EventGateway()
    first = {"type": "open", "body": {"name": "alpha"}}
    second = {"type": "close", "body": {"name": "beta"}}
    wire = sender.outbound(first) + sender.outbound(second)
    assert receiver.feed(wire) == [first, second]
